const { db } = require('../config/database');

class Leaderboard {
  // 生成个人排行榜
  static async generateUserLeaderboard(period = 'daily', date = null) {
    if (!date) {
      date = new Date().toISOString().split('T')[0];
    }
    
    let startDate, endDate;
    const targetDate = new Date(date);
    
    switch (period) {
      case 'daily':
        startDate = targetDate.toISOString().split('T')[0];
        endDate = startDate;
        break;
      case 'weekly':
        const weekStart = new Date(targetDate);
        weekStart.setDate(targetDate.getDate() - targetDate.getDay());
        startDate = weekStart.toISOString().split('T')[0];
        const weekEnd = new Date(weekStart);
        weekEnd.setDate(weekStart.getDate() + 6);
        endDate = weekEnd.toISOString().split('T')[0];
        break;
      case 'monthly':
        startDate = `${targetDate.getFullYear()}-${String(targetDate.getMonth() + 1).padStart(2, '0')}-01`;
        const monthEnd = new Date(targetDate.getFullYear(), targetDate.getMonth() + 1, 0);
        endDate = monthEnd.toISOString().split('T')[0];
        break;
      default:
        throw new Error('无效的排行榜周期');
    }
    
    // 获取用户在指定时间段内的像素统计
    const rankings = await db('users')
      .select(
        'users.id',
        'users.username',
        'users.avatar_url',
        db.raw('COALESCE(SUM(CASE WHEN pixels.created_at::date BETWEEN ? AND ? THEN 1 ELSE 0 END), 0) as period_pixels', [startDate, endDate]),
        db.raw('COALESCE(COUNT(pixels.id), 0) as total_pixels'),
        db.raw('COALESCE(COUNT(DISTINCT CASE WHEN pixels.created_at::date BETWEEN ? AND ? THEN pixels.grid_id END), 0) as current_pixels', [startDate, endDate])
      )
      .leftJoin('pixels', 'users.id', 'pixels.user_id')
      .groupBy('users.id', 'users.username', 'users.avatar_url')
      .orderBy('period_pixels', 'desc')
      .orderBy('total_pixels', 'desc')
      .limit(100);
    
    // 保存排行榜数据
    await this.saveLeaderboard('user', period, date, rankings);
    
    return rankings;
  }

  // 生成联盟排行榜
  static async generateAllianceLeaderboard(period = 'daily', date = null) {
    if (!date) {
      date = new Date().toISOString().split('T')[0];
    }
    
    let startDate, endDate;
    const targetDate = new Date(date);
    
    switch (period) {
      case 'daily':
        startDate = targetDate.toISOString().split('T')[0];
        endDate = startDate;
        break;
      case 'weekly':
        const weekStart = new Date(targetDate);
        weekStart.setDate(targetDate.getDate() - targetDate.getDay());
        startDate = weekStart.toISOString().split('T')[0];
        const weekEnd = new Date(weekStart);
        weekEnd.setDate(weekStart.getDate() + 6);
        endDate = weekEnd.toISOString().split('T')[0];
        break;
      case 'monthly':
        startDate = `${targetDate.getFullYear()}-${String(targetDate.getMonth() + 1).padStart(2, '0')}-01`;
        const monthEnd = new Date(targetDate.getFullYear(), targetDate.getMonth() + 1, 0);
        endDate = monthEnd.toISOString().split('T')[0];
        break;
      default:
        throw new Error('无效的排行榜周期');
    }
    
    // 获取联盟在指定时间段内的像素统计
    const rankings = await db('alliances')
      .select(
        'alliances.id',
        'alliances.name',
        'alliances.color',
        'alliances.banner_url',
        db.raw('COALESCE(SUM(CASE WHEN pixels.created_at::date BETWEEN ? AND ? THEN 1 ELSE 0 END), 0) as period_pixels', [startDate, endDate]),
        db.raw('COALESCE(COUNT(pixels.id), 0) as total_pixels'),
        db.raw('COALESCE(COUNT(DISTINCT CASE WHEN pixels.created_at::date BETWEEN ? AND ? THEN pixels.grid_id END), 0) as current_pixels', [startDate, endDate]),
        db.raw('COUNT(DISTINCT alliance_members.user_id) as member_count')
      )
      .leftJoin('alliance_members', 'alliances.id', 'alliance_members.alliance_id')
      .leftJoin('pixels', 'alliance_members.user_id', 'pixels.user_id')
      .where('alliances.is_active', true)
      .groupBy('alliances.id', 'alliances.name', 'alliances.color', 'alliances.banner_url')
      .orderBy('period_pixels', 'desc')
      .orderBy('total_pixels', 'desc')
      .limit(50);
    
    // 保存排行榜数据
    await this.saveLeaderboard('alliance', period, date, rankings);
    
    return rankings;
  }

  // 保存排行榜数据
  static async saveLeaderboard(type, period, date, rankings) {
    await db('leaderboards')
      .insert({
        type,
        period,
        date,
        rankings: JSON.stringify(rankings)
      })
      .onConflict(['type', 'period', 'date'])
      .merge(['rankings', 'updated_at']);
  }

  // 获取排行榜
  static async getLeaderboard(type, period, date = null, limit = 20) {
    if (!date) {
      date = new Date().toISOString().split('T')[0];
    }
    
    const leaderboard = await db('leaderboards')
      .where({
        type,
        period,
        date
      })
      .first();
    
    if (!leaderboard) {
      // 如果不存在，生成新的排行榜
      if (type === 'user') {
        await this.generateUserLeaderboard(period, date);
      } else if (type === 'alliance') {
        await this.generateAllianceLeaderboard(period, date);
      }
      
      // 重新获取
      const newLeaderboard = await db('leaderboards')
        .where({
          type,
          period,
          date
        })
        .first();
      
      if (newLeaderboard) {
        const rankings = JSON.parse(newLeaderboard.rankings);
        return rankings.slice(0, limit);
      }
      
      return [];
    }
    
    const rankings = JSON.parse(leaderboard.rankings);
    return rankings.slice(0, limit);
  }

  // 获取用户排名
  static async getUserRank(userId, type = 'user', period = 'daily', date = null) {
    if (!date) {
      date = new Date().toISOString().split('T')[0];
    }
    
    const leaderboard = await this.getLeaderboard(type, period, date, 1000);
    
    const userRank = leaderboard.findIndex(item => item.id === userId);
    
    if (userRank === -1) {
      return null;
    }
    
    return {
      rank: userRank + 1,
      data: leaderboard[userRank]
    };
  }

  // 获取联盟排名
  static async getAllianceRank(allianceId, period = 'daily', date = null) {
    if (!date) {
      date = new Date().toISOString().split('T')[0];
    }
    
    const leaderboard = await this.getLeaderboard('alliance', period, date, 1000);
    
    const allianceRank = leaderboard.findIndex(item => item.id === allianceId);
    
    if (allianceRank === -1) {
      return null;
    }
    
    return {
      rank: allianceRank + 1,
      data: leaderboard[allianceRank]
    };
  }

  // 获取排行榜历史
  static async getLeaderboardHistory(type, period, limit = 7) {
    const history = await db('leaderboards')
      .where({
        type,
        period
      })
      .orderBy('date', 'desc')
      .limit(limit);
    
    return history.map(item => ({
      date: item.date,
      rankings: JSON.parse(item.rankings).slice(0, 10) // 只返回前10名
    }));
  }

  // 清理旧排行榜数据
  static async cleanupOldLeaderboards(daysToKeep = 30) {
    const cutoffDate = new Date();
    cutoffDate.setDate(cutoffDate.getDate() - daysToKeep);
    
    const deleted = await db('leaderboards')
      .where('created_at', '<', cutoffDate)
      .del();
    
    return deleted;
  }
}

module.exports = Leaderboard;
